import { isDateRange, isNumericRange } from './type-guards.js';
import { formatResolution } from '../../../../tooltip/utils/resolution-formatter.js';
import type { HeaderData } from '../../../types.js';

const DISPLAY_UNITS_LIMIT = 3;
export const getDurationContent = (
  showRangeDuration: boolean,
  value: HeaderData,
) => {
  if (!showRangeDuration) {
    return null;
  }

  if (isDateRange(value)) {
    return formatResolution(value[0], value[1], DISPLAY_UNITS_LIMIT);
  }

  if (isNumericRange(value)) {
    return Math.abs(value[1] - value[0]);
  }

  return null;
};
